// Parse the action tag from the subject line
const ROUTES = [
  { pattern: /\[OPPORTUNITY_RE_FASTSCAN\]/i, taskType: 'OPPORTUNITY_RE_FASTSCAN', priority: 'HIGH', hitl: false },
  { pattern: /\[LEGAL_REVIEW\]/i, taskType: 'LEGAL_REVIEW', priority: 'HIGH', hitl: true, timeoutMin: 120 },
  { pattern: /\[DRAFT_REPLY\]/i, taskType: 'DRAFT_REPLY', priority: 'MEDIUM', hitl: true, timeoutMin: 60 },
  { pattern: /\[FOLLOW.?UP/i, taskType: 'FOLLOW_UP', priority: 'MEDIUM', hitl: true, timeoutMin: 240 },
  { pattern: /\[SCHEDULING\]/i, taskType: 'SCHEDULING', priority: 'MEDIUM', hitl: true, timeoutMin: 60 },
  { pattern: /\[CONSTRUCTION_REVIEW\]/i, taskType: 'CONSTRUCTION_REVIEW', priority: 'MEDIUM', hitl: false },
  { pattern: /\[FINANCE_REVIEW\]/i, taskType: 'FINANCE_REVIEW', priority: 'MEDIUM', hitl: false },
  { pattern: /\[ESCALATE/i, taskType: 'ESCALATE_TO_JR', priority: 'URGENT', hitl: true, timeoutMin: 30 },
];

const results = [];
for (const item of $input.all()) {
  const subject = item.json.subject || '';
  let matched = null;

  for (const route of ROUTES) {
    if (route.pattern.test(subject)) {
      matched = route;
      break;
    }
  }

  if (!matched) matched = { taskType: 'GENERAL', priority: 'LOW', hitl: false };

  results.push({
    json: {
      ...item.json,
      taskType: matched.taskType,
      priority: matched.priority,
      hitlRequired: matched.hitl,
      hitlTimeoutMin: matched.timeoutMin || null,
      amandaTask: {
        taskType: matched.taskType,
        priority: matched.priority,
        hitlRequired: matched.hitl,
        hitlTimeoutMin: matched.timeoutMin || null,
        metadata: {
          messageId: item.json.id,
          threadId: item.json.threadId,
          timestamp: new Date().toISOString(),
          routedBy: 'OpenClaw n8n v1.0',
        },
        email: {
          subject: item.json.subject,
          from: item.json.from,
          to: item.json.to,
          date: item.json.date,
          bodyPreview: (item.json.text || '').substring(0, 2000),
        },
      },
    },
  });
}

return results;
